import json, re

html = open("/home/user/myproject/chart.html").read()

# Extract the embedded Vega-Lite spec (Altair embeds it as a JSON literal)
# Pattern: vegaEmbed('#vis', <spec>, ...)
m = re.search(r'vegaEmbed\(.*?,\s*(\{.*\})\s*,\s*\{', html, re.DOTALL)
if not m:
    # fallback: look for the spec object directly
    m = re.search(r'var spec\s*=\s*(\{.*?\});', html, re.DOTALL)
if not m:
    print("FAIL: could not find embedded spec")
    exit(1)

spec = json.loads(m.group(1))

# ── helper: flatten nested lists/dicts to find things ────────────────────────
def find_all(obj, key):
    """Recursively yield all values for `key` found anywhere in obj."""
    if isinstance(obj, dict):
        if key in obj:
            yield obj[key]
        for v in obj.values():
            yield from find_all(v, key)
    elif isinstance(obj, list):
        for item in obj:
            yield from find_all(item, key)

def find_all_objects(obj):
    """Yield every dict found anywhere in obj."""
    if isinstance(obj, dict):
        yield obj
        for v in obj.values():
            yield from find_all_objects(v)
    elif isinstance(obj, list):
        for item in obj:
            yield from find_all_objects(item)

# ── 1. Top-level layer array with at least 3 entries ─────────────────────────
layers = spec.get("layer", [])
assert len(layers) >= 3, f"FAIL: need >=3 layers, got {len(layers)}"
print(f"PASS: {len(layers)} layers found")

# ── 2. Window transform: mean(price), groupby symbol, frame [-15,15] ─────────
window_found = False
for obj in find_all_objects(spec):
    if "window" in obj and isinstance(obj["window"], list):
        for w in obj["window"]:
            if w.get("op") == "mean" and w.get("field") == "price":
                frame = obj.get("frame", [])
                groupby = obj.get("groupby", [])
                if frame == [-15, 15] and "symbol" in groupby:
                    window_found = True
                    print(f"PASS: window transform found — frame={frame}, groupby={groupby}")
assert window_found, "FAIL: window transform (mean price, grouped by symbol, frame [-15,15]) not found"

# ── 3. JoinAggregate transform: mean(price), grouped by symbol, used in a dashed rule ──
ja_field = None
for obj in find_all_objects(spec):
    if "joinaggregate" in obj and isinstance(obj["joinaggregate"], list):
        for ja in obj["joinaggregate"]:
            if ja.get("op") == "mean" and ja.get("field") == "price":
                groupby = obj.get("groupby", [])
                if "symbol" in groupby:
                    ja_field = ja.get("as")
                    print(f"PASS: joinaggregate transform found — field '{ja_field}', groupby={groupby}")
assert ja_field is not None, "FAIL: joinaggregate (mean price, grouped by symbol) not found"

# Verify a rule mark with strokeDash references ja_field
rule_dashed = False
for obj in find_all_objects(spec):
    mark = obj.get("mark", {})
    if isinstance(mark, dict) and mark.get("type") == "rule":
        stroke_dash = mark.get("strokeDash")
        if stroke_dash:
            rule_dashed = True
            print(f"PASS: dashed rule mark found — strokeDash={stroke_dash}")
assert rule_dashed, "FAIL: dashed rule mark not found"

# ── 4. Params: select input with correct options ──────────────────────────────
tickers = ["MSFT", "AMZN", "IBM", "GOOG", "AAPL"]
select_param_found = False
for params_list in find_all(spec, "params"):
    if not isinstance(params_list, list):
        continue
    for p in params_list:
        bind = p.get("bind", {})
        if isinstance(bind, dict) and bind.get("input") == "select":
            opts = bind.get("options", [])
            if sorted(opts) == sorted(tickers):
                select_param_found = True
                print(f"PASS: select param found — name='{p.get('name')}', options={opts}")
assert select_param_found, "FAIL: select param with correct ticker options not found"

# ── 5. Filter transform referencing the parameter ────────────────────────────
filter_found = False
for obj in find_all_objects(spec):
    tf = obj.get("filter", "")
    if isinstance(tf, str) and "symbol_selection" in tf:
        filter_found = True
        print(f"PASS: filter transform referencing symbol_selection — '{tf}'")
assert filter_found, "FAIL: filter transform referencing symbol_selection not found"

# ── 6. Interval selection bound to scales ────────────────────────────────────
scales_found = False
for p in find_all_objects(spec):
    if p.get("bind") == "scales" and p.get("select", {}).get("type") == "interval":
        scales_found = True
        print(f"PASS: interval selection bound to scales found — name='{p.get('name')}'")
assert scales_found, "FAIL: interval selection bound to scales not found"

# ── HTML artefacts ────────────────────────────────────────────────────────────
select_tag = "<select" in html
print(f"PASS: <select> element in HTML: {select_tag}")

print("\n✅  All acceptance criteria met.")
PYEOF
